# Random ID and Password for RDS instances
resource "random_id" "suffix" {
  byte_length = 4
}

resource "random_password" "db" {
  length  = 16
  special = false
}

# VPC and Subnets required for RDS and Private Hosted Zone
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "private" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
}

# DB Subnet Group named "main"
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.private.id, aws_subnet.public.id]
}

# Internal RDS Instance (Accessible within VPC)
resource "aws_db_instance" "internal" {
  identifier          = "internal"
  allocated_storage   = 20
  engine              = "mysql"
  instance_class      = "db.t2.micro"
  db_name             = "internaldb"
  username            = "admin"
  password            = random_password.db.result
  db_subnet_group_name = aws_db_subnet_group.main.name
  skip_final_snapshot = true
  publicly_accessible  = false
}

# Public RDS Instance (Accessible publicly)
resource "aws_db_instance" "public" {
  identifier          = "public"
  allocated_storage   = 20
  engine              = "mysql"
  instance_class      = "db.t2.micro"
  db_name             = "publicdb"
  username            = "admin"
  password            = random_password.db.result
  db_subnet_group_name = aws_db_subnet_group.main.name
  skip_final_snapshot = true
  publicly_accessible  = true
}

# Private Route 53 Hosted Zone (resolves inside VPC)
resource "aws_route53_zone" "private" {
  name = "private"
  vpc {
    vpc_id = aws_vpc.main.id
  }
}

# Public Route 53 Hosted Zone (resolves publicly)
resource "aws_route53_zone" "public" {
  name = "public"
}

# DNS Record pointing to Internal DB
resource "aws_route53_record" "internal_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.endpoint]
}

# DNS Record pointing to Public DB
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "db"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.endpoint]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region = "us-east-1" 
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# Create a VPC for internal resources
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/24"
}


# RDS instances
resource "aws_db_instance" "internal" {
  # Internal DB configuration
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier =  "internal"
  username             = "user"
  password             = "password"
  db_subnet_group_name = aws_db_subnet_group.main.name
  skip_final_snapshot  = true
}

resource "aws_db_instance" "public" {
  # Public DB configuration
  publicly_accessible  = true
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier = "public"
  username             = "user"
  password             = "password"
  skip_final_snapshot  = true
}

resource "aws_db_subnet_group" "main" {
