resource "aws_iam_role" "example" {
  name = "example-codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "example" {
  role       = aws_iam_role.example.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
}

resource "aws_codebuild_project" "example" {
  name         = "example-project"
  service_role = aws_iam_role.example.arn
  description  = "Example CodeBuild project with secondary sources"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false
  }

  source {
    type     = "GITHUB"
    location = "https://github.com/user/repo.git"
  }

  secondary_sources {
    type              = "S3"
    location          = "my-bucket/secondary-source.zip"
    source_identifier = "secondary_source_1"
  }

  secondary_sources {
    type              = "CODECOMMIT"
    location          = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/MyOtherRepo"
    source_identifier = "secondary_source_2"
    git_clone_depth   = 1
  }

  source_version = "main"
}
```

