  filename         = "pizza_order.zip"
  function_name    = "PizzaOrderFunction"
  role            = aws_iam_role.lambda_role.arn
  handler         = "index.handler"
  source_code_hash = filebase64sha256("pizza_order.zip")
  runtime         = "nodejs18.x"
}

resource "aws_iam_role" "lex_role" {
  name = "pizza-order-lex-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "lex.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_policy" {
  role       = aws_iam_role.lex_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotPolicy"
}

resource "aws_iam_role_policy" "lex_lambda_invoke" {
  name = "lex-lambda-invoke"
  role = aws_iam_role.lex_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "lambda:InvokeFunction"
        Effect = "Allow"
        Resource = aws_lambda_function.pizza_order.arn
      }
    ]
  })
}

resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order.function_name
  principal     = "lex.amazonaws.com"
}

resource "aws_lex_intent" "order_pizza" {
  name           = "OrderPizza"
  create_version = true

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri            = aws_lambda_function.pizza_order.arn
      message_version = "1.0"
    }
  }

  sample_utterances = [
    "I want to order a pizza",
    "Order pizza",
    "Get me a pizza"
  ]
}

resource "aws_lex_bot" "pizza_bot" {
  child_directed  = false
  name            = "PizzaOrderBot"
  process_behavior = "BUILD"
  voice_id        = "Salli"
  locale          = "en-US"

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  clarification_prompt {
    max_attempts = 2
    messages {
      content      = "I didn't understand you. What type of pizza would you like to order?"
      content_type = "PlainText"
    }
  }

  abort_statement {
    messages {
      content      = "Sorry, I could not understand your order."
      content_type = "PlainText"
    }
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lambda_permission" "allow_lex_to_start_execution" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.hello_pizza.function_name
  principal     = "lex.amazonaws.com"
  # source_arn    = "${aws_lex_bot.order_pizza.arn}:$LATEST"
}

data "archive_file" "hello_pizza" {
  type        = "zip"
  source_file = "./supplement/hello_pizza.py"
  output_path = "./supplement/hello_pizza.zip"
}

resource "aws_lambda_function" "hello_pizza" {
  function_name = "hello_pizza"
  role          = aws_iam_role.iam_exec_role.arn
  filename      = data.archive_file.hello_pizza.output_path
  source_code_hash = data.archive_file.hello_pizza.output_base64sha256
  handler       = "hello_pizza.handler"
  runtime       = "python3.12"
}

resource "aws_iam_role" "iam_exec_role" {
  name = "iam-exec-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_lex_intent" "OrderPizza" {
  name = "OrderPizza"

  sample_utterances = [
    "I would like to pick up a pizza",
    "I would like to order some pizzas",
  ]

  slot {
    name                     = "PizzaType"
    description              = "Type of pizza to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1
    value_elicitation_prompt {
      message {
        content             = "What type of pizza would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri            = aws_lambda_function.hello_pizza.arn
      message_version = "1.0"
    }
  }
}

resource "aws_lex_bot" "order_pizza" {
  name     = "OrderPizza"
  description  = "Orders a pizza from a local pizzeria"

  idle_session_ttl_in_seconds = 600
  locale = "en-US"

  child_directed = false

  voice_id = "Salli"
  process_behavior = "BUILD"

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand that, can you please repeat?"
      content_type = "PlainText"
    }
  }

  abort_statement {
    message {
      content      = "Sorry, I could not understand. Goodbye."
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.OrderPizza.name
    intent_version = aws_lex_intent.OrderPizza.version
  }

  # depends_on = [aws_lambda_permission.allow_lex_to_start_execution]
}

