resource "random_pet" "id" {
  keepers = {
    # Generate a new id each time the configuration changes
    id = timestamp()
  }
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "firehose-vpc"
  }
}

resource "aws_subnet" "example" {
  vpc_id     = aws_vpc.example.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "firehose-subnet"
  }
}

resource "aws_security_group" "es_sg" {
  name        = "firehose-es-sg"
  description = "Allow traffic for Firehose to ES"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.example.cidr_block]
  }

  tags = {
    Name = "firehose-es-sg"
  }
}

resource "aws_s3_bucket" "bucket" {
  bucket = "firehose-backup-bucket-${random_pet.id.id}"
}

resource "aws_iam_role" "firehose_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "firehose.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  role = aws_iam_role.firehose_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.bucket.arn,
          "${aws_s3_bucket.bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut"
        ]
        Resource = "${aws_elasticsearch_domain.example.arn}/*"
      },
      {
        Effect = "Allow"
        Action = "iam:PassRole"
        Resource = aws_iam_role.firehose_role.arn
      }
    ]
  })
}

resource "aws_iam_role" "firehose_vpc_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_vpc_attach" {
  role       = aws_iam_role.firehose_vpc_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSFirehoseServiceRoleForVPC"
}

resource "aws_elasticsearch_domain" "example" {
  domain_name           = "firehose-es-${random_pet.id.id}"
  elasticsearch_version = "7.10"

  cluster_config {
    instance_type = "t2.small.elasticsearch"
  }

  ebs_options {
    volume_size = 10
  }

  vpc_options {
    subnet_ids = [aws_subnet.example.id]
    security_group_ids = [aws_security_group.es_sg.id]
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "es:ESHttp*"
        Effect = "Allow"
        Principal = { AWS = aws_iam_role.firehose_role.arn }
        Resource = "${aws_elasticsearch_domain.example.arn}/*"
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "example" {
  name        = "firehose-es-stream"
  destination = "elasticsearch"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.bucket.arn
  }

  elasticsearch_destination {
    domain_arn = aws_elasticsearch_domain.example.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-index"
    # s3_backup_mode defaults to FailedDocumentsOnly
  }

  vpc_config {
    subnet_ids         = [aws_subnet.example.id]
    security_group_ids = [aws_security_group.es_sg.id]
    role_arn           = aws_iam_role.firehose_vpc_role.arn
  }
}
```

