resource "aws_iam_role" "firehose" {
  name = "firehose_opensearch_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_policy"
  role = aws_iam_role.firehose.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.example.arn,
          "${aws_s3_bucket.example.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost"
        ]
        Resource = "${aws_opensearch_domain.example.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeVpcAttribute",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_opensearch_domain" "example" {
  domain_name    = "firehose-domain"
  engine_version = "OpenSearch_1.0"

  cluster_config {
    instance_type = "t3.small.search"
  }

  vpc_options {
    subnet_ids         = [aws_subnet.example.id]
    security_group_ids = [aws_security_group.example.id]
  }

  ebs_options {
    volume_size = 10
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["es:ESHttp*"]
        Effect   = "Allow"
        Principal = { AWS = aws_iam_role.firehose.arn }
        Resource = "${aws_opensearch_domain.example.arn}/*"
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "example" {
  name        = "example-firehose-stream"
  destination = "opensearch"

  opensearch_domain_configuration {
    domain_arn     = aws_opensearch_domain.example.arn
    role_arn       = aws_iam_role.firehose.arn
    index_name     = "firehose-index"
    s3_backup_mode = "FailedDocumentsOnly"

    s3_configuration {
      bucket_arn = aws_s3_bucket.example.arn
      role_arn   = aws_iam_role.firehose.arn
      prefix     = "data/"
    }

    s3_backup_configuration {
      bucket_arn = aws_s3_bucket.example.arn
      role_arn   = aws_iam_role.firehose.arn
      prefix     = "backup/"
    }
  }
}
