data "aws_caller_identity" "current" {}

# Variable for the ECR repository name
variable "ecr_repository_name" {
  default = "my-app-repo"
  description = "The name of the ECR repository to lookup the stable image from"
}

# Lookup the most recent stable ECR image
data "aws_ecr_image" "stable" {
  repository_name = var.ecr_repository_name
  image_tag       = "stable"

  # This ensures we get the image pushed last if there are multiple with the same tag
  most_recent = true
}

locals {
  # Determine image tag: use ECR data if available, otherwise fallback
  image_tag     = try(data.aws_ecr_image.stable.image_tag, "latest")

  # Standard AWS tags to apply to resources
  aws_tags = {
    ManagedBy   = "Terraform"
    Environment = terraform.workspace
    Project     = "eks-demo"
  }

  # Workspace name for naming conventions
  workspace_name = terraform.workspace
}

# Basic networking resources required for the EKS module example
resource "aws_vpc" "eks_vpc" {
  cidr_block = "10.0.0.0/16"
  tags       = local.aws_tags
}

resource "aws_subnet" "eks_subnet" {
  vpc_id     = aws_vpc.eks_vpc.id
  cidr_block = "10.0.1.0/24"
  tags       = local.aws_tags
}

# EKS Module for Cluster Provisioning
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.17"

  cluster_name    = "${local.workspace_name}-cluster"
  cluster_version = "1.27"

  vpc_id     = aws_vpc.eks_vpc.id
  subnet_ids = [aws_subnet.eks_subnet.id]

  # Cluster IAM Role settings
  cluster_endpoint_public_access  = true

  # Enable EKS Add-ons if necessary
  cluster_addons = {
    coredns = {
      most_recent = true
    }
    kube-proxy = {
      most_recent = true
    }
    vpc-cni = {
      most_recent = true
    }
  }

  # EKS Managed Node Group settings
  eks_managed_node_groups = {
    default_node_group = {
      name = "${local.workspace_name}-node-group"

      # Instance types and scaling settings
      instance_types = ["t3.medium"]
      desired_size   = 2
      min_size       = 1
      max_size       = 3

      # IAM Role settings for the Node Group
      create_iam_role = true
      iam_role_arns   = [] # Attach additional policies here if needed

      tags = local.aws_tags
    }
  }

  tags = local.aws_tags
}

# Fetch EKS Cluster metadata
data "aws_eks_cluster" "cluster" {
  name = module.eks.cluster_name
}

# Fetch EKS Cluster authentication token
data "aws_eks_cluster_auth" "cluster" {
  name = module.eks.cluster_name
}

# Configure Kubernetes Provider using EKS data
provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

# Configure Helm Provider using Kubernetes Provider
provider "helm" {
  kubernetes {
    host                   = data.aws_eks_cluster.cluster.endpoint
    cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
    token                  = data.aws_eks_cluster_auth.cluster.token
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

variable "cluster_name" {
  type = string
  default = "test-cluster"
}

data "aws_region" "current" {}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "test_eks_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  availability_zone = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "test_eks_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"

  availability_zone = data.aws_availability_zones.available.names[1]
}

resource "aws_iam_role" "example" {
  name = "${var.cluster_name}-eks"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.example.name
}

resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.example.name
}

resource "aws_eks_cluster" "example" {
  name     = var.cluster_name
  role_arn = aws_iam_role.example.arn

  vpc_config {
    subnet_ids = [ aws_subnet.test_eks_1.id, aws_subnet.test_eks_2.id ]
  }

  # Ensure that IAM Role permissions are created before and deleted after EKS Cluster handling.
  # Otherwise, EKS will not be able to properly delete EKS managed EC2 infrastructure such as Security Groups.
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy,
  ]

  # Manage kubectl configuration
  provisioner "local-exec" {
    command = "aws eks --region ${data.aws_region.current.name} update-kubeconfig --name ${self.name}"
  }

  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config unset users.${self.arn}"
  }
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config unset clusters.${self.arn}"
  }
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config unset contexts.${self.arn}"
  }
}

