  bucket     = aws_s3_bucket.cloudgoat_data.id
  acl        = "private"
}

resource "aws_s3_bucket" "website_data" {
  bucket = "website-data-${var.bucket_suffix}"
}

resource "aws_s3_object" "upload" {
  bucket = aws_s3_bucket.website_data.id
  key    = "order_data2.csv"
  source = "order_data2.csv"
}

resource "aws_s3_bucket_public_access_block" "website_block" {
  bucket = aws_s3_bucket.website_data.id

  block_public_acls       = true
  ignore_public_acls      = true
  restrict_public_buckets = true
  block_public_policy     = false # Set to false to allow the bucket policy to be attached
}

resource "aws_s3_bucket_policy" "website_policy" {
  bucket = aws_s3_bucket.website_data.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.website_data.arn}/*"
      }
    ]
  })
}

