```hcl
resource "random_id" "suffix" {
  byte_length = 4
}

# VPC and Networking Setup (Required for MSK)
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}-${random_id.suffix.hex}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_security_group" "msk_sg" {
  name        = "msk-sg-${random_id.suffix.hex}"
  description = "Security group for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# KMS Key for Encryption at Rest
resource "aws_kms_key" "msk_encryption" {
  description             = "KMS key for MSK cluster encryption at rest"
  deletion_window_in_days = 10
}

# Log Destinations

# 1. CloudWatch Logs Group
resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "/aws/msk/logs-${random_id.suffix.hex}"
}

# 2. S3 Bucket for S3 Logging
resource "aws_s3_bucket" "msk_log_bucket" {
  bucket = "msk-log-bucket-${random_id.suffix.hex}"
}

# 3. Kinesis Data Firehose Delivery Stream
# Firehose requires an IAM role and a destination (usually an S3 bucket)
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-dest-${random_id.suffix.hex}"
}

resource "aws_iam_role" "firehose_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic policy to Firehose role to allow writing to S3
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk_stream" {
  name        = "msk-firehose-stream-${random_id.suffix.hex}"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
  }
}

# Amazon MSK Cluster
resource "aws_msk_cluster" "main" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 1000 # GB
      }
    }
  }

  # Encryption at Rest
  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption.arn
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
      in_cluster    = true
    }
  }

  # Open Monitoring
  open_monitoring {
    prometheus_jmx_exporter {
      enabled = true
    }
  }

  # Logging Configuration
  logging_info {
    broker_logs {
      # CloudWatch Logs
      cloudwatch_logs {
        log_group_arn = aws_cloudwatch_log_group.msk_logs.arn
        enabled       = true
      }

      # S3 Logs
      s3 {
        bucket  = aws_s3_bucket.msk_log_bucket.id
        prefix  = "logs/msk-"
        enabled = true
      }

      # Firehose Logs
      firehose {
        delivery_stream_arn = aws_kinesis_firehose_delivery_stream.msk_stream.arn
        enabled             = true
      }
    }
  }
}
```

