provider "aws" {
  region = "us-east-1"
}

# Networking resources required for MSK
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet" {
  count             = 2
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# IAM Role for the MSK Connect Connector
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonMSKConnectFullAccess"
}

# S3 Bucket to store the plugin
resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-connect-plugins-bucket"
}

resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip" # Assumes this file exists locally or remove for remote logic
}

# MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.small"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]
  }
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium" {
  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3_bucket_name = aws_s3_bucket.plugin_bucket.id
    s3_object_key  = aws_s3_object.debezium_plugin.key
  }
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "example" {
  name = "debezium-connector"

  capacity {
    provisioned {
      worker_count = 1
      mcu_count    = 1
    }
  }

  connector_configuration = {
    # Example configuration keys for Debezium
    "database.hostname" = "your-database-host"
    "database.port"     = "5432"
    "database.user"     = "user"
    "database.password" = "password"
    "database.db.name"  = "db"
    "topic.prefix"      = "debezium"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers
    }

    vpc {
      subnet_ids = [aws_subnet.msk_subnet[0].id]
      security_groups = [aws_security_group.msk_sg.id]
    }
  }

  kafka_client_authentication {
    authentication_type = "NONE"
  }

  kafka_endpoint {
    authentication_type = "PLAINTEXT"
  }

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled = true
      }
    }
  }

  plugin_location {
    plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}

