  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3_bucket_name = aws_s3_bucket.plugin_bucket.id
    s3_object_key  = aws_s3_object.debezium_plugin.key
  }
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "example" {
  name = "debezium-connector"

  capacity {
    provisioned {
      worker_count = 1
      mcu_count    = 1
    }
  }

  connector_configuration = {
    # Example configuration keys for Debezium
    "database.hostname" = "your-database-host"
    "database.port"     = "5432"
    "database.user"     = "user"
    "database.password" = "password"
    "database.db.name"  = "db"
    "topic.prefix"      = "debezium"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers
    }

    vpc {
      subnet_ids = [aws_subnet.msk_subnet[0].id]
      security_groups = [aws_security_group.msk_sg.id]
    }
  }

  kafka_client_authentication {
    authentication_type = "NONE"
  }

  kafka_endpoint {
    authentication_type = "PLAINTEXT"
  }

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled = true
      }
    }
  }

  plugin_location {
    plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}
