      bucket_arn = aws_s3_bucket.logs.arn
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }
}

resource "aws_mskconnect_connector" "main" {
  name              = "debezium-connector"
  kafkacluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.main.bootstrap_brokers_sasl_scram
      vpc {
        subnet_ids = aws_subnet.main[*].id
        security_groups = [aws_security_group.msk.id]
      }
    }
  }

  kafka_client_authentication {
    authentication_type = "NONE"
  }

  kafkaconnect_version = "2.8.1"
  capacity {
    provisioned {
      worker_count = 1
      mcu_count    = 1
    }
  }

  connector_configuration = {
    "database.hostname" = "localhost"
    "database.port"     = "5432"
    "database.user"     = "user"
    "database.password" = "password"
    "database.dbname"   = "mydb"
    "topic.prefix"      = "debezium"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium.arn
      revision = aws_mskconnect_custom_plugin.debezium.latest_revision
    }
  }
}
```

