resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Allow access only from the two specific subnets"
  vpc_id      = aws_vpc.main.id

  # Ingress rule: Allow Neptune port (8182) only from the specific sample subnets
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_1.cidr_block, aws_subnet.subnet_2.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

