resource "random_id" "autograder" {
  byte_length = 4
}

resource "aws_iam_role" "codebuild" {
  name = "codebuild-autograder-${random_id.autograder.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_logs" {
  role       = aws_iam_role.codebuild.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
}

resource "aws_cloudwatch_log_group" "autograder" {
  name              = "autograder-${random_id.autograder.hex}"
  retention_in_days = 14
}

resource "aws_codebuild_source_credential" "github" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token # Pass your GitHub token via variable
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-${random_id.autograder.hex}"
  description   = "Autograding system for student submissions"
  service_role  = aws_iam_role.codebuild.name
  build_timeout = "10"

  source {
    type                = "GITHUB"
    location            = "https://github.com/your-org/student-repo.git"
    git_clone_depth     = 1
    report_build_status = true
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:5.0"
    type         = "LINUX_CONTAINER"

    environment_variable {
      name  = "TEST_SCRIPT"
      value = "grade.sh"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = aws_cloudwatch_log_group.autograder.name
      status     = "ENABLED"
    }
  }

  source_version = "main"

  buildspec = <<-EOF
    version: 0.2
    phases:
      install:
        runtime-versions:
          python: 3.9
      pre_build:
        commands:
          - echo "Preparing environment..."
          - pip install pytest
      build:
        commands:
          - echo "Executing grading tests..."
          - chmod +x $TEST_SCRIPT
          - ./$TEST_SCRIPT
      post_build:
        commands:
          - echo "Grading finished successfully."
    EOF
}

