resource "aws_s3_bucket" "grading_artifacts" {
  bucket = "autograding-submission-results"
}

resource "aws_vpc" "autograder_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "private_subnet" {
  vpc_id     = aws_vpc.autograder_vpc.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "autograder-private-subnet"
  }
}

resource "aws_security_group" "no_internet_sg" {
  name        = "no_internet_access"
  description = "Security group that blocks all outbound traffic to ensure no internet access for student code."
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress rules defined here, which by default denies all outbound traffic (0.0.0.0/0).
  # This prevents the student code from accessing the internet.
}

# VPC Gateway Endpoint for S3 to allow saving grading results without general internet access
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"

  tags = {
    Name = "s3-endpoint"
  }
}

resource "aws_vpc_endpoint_subnet_association" "s3_endpoint_association" {
  vpc_endpoint_id = aws_vpc_endpoint.s3_endpoint.id
  subnet_id       = aws_subnet.private_subnet.id
}

resource "aws_iam_role" "codebuild_role" {
  name = "autograder_codebuild_role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "codebuild.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "codebuild_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

resource "aws_iam_role_policy_attachment" "vpc_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonVPCFullAccess"
}

resource "aws_codebuild_project" "autograder" {
  name         = "cs-course-autograder"
  description  = "Build project to execute student submissions in an isolated VPC."
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_artifacts.id
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example-org/student-repo.git"
    git_clone_depth = 1
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "GRADES_OUTPUT"
      value = "results.json"
    }
  }

  # Configure VPC for isolation
  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id

    subnets = [
      aws_subnet.private_subnet.id,
    ]

    security_group_ids = [
      aws_security_group.no_internet_sg.id,
    ]
  }
}

