  name        = "autograder-sg"
  description = "Security group for the autograder CodeBuild environment"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress rules defined creates a deny-all egress, blocking outbound internet access
  # Inbound rules are managed by CodeBuild for the service-linked ENIs
}

resource "aws_s3_bucket" "autograder_artifacts" {
  bucket = "autograder-results-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "autograder-artifacts"
  }
}

resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3" # Replace region if necessary

  tags = {
    Name = "s3-endpoint"
  }
}

resource "aws_vpc_endpoint_route_table_association" "s3_route" {
  route_table_id  = aws_vpc.autograder_vpc.default_route_table_id
  vpc_endpoint_id = aws_vpc_endpoint.s3_endpoint.id
}

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "codebuild.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "*"
    },
    {
      "Effect": "Allow",
      "Action": [
        "s3:PutObject",
        "s3:GetObject",
        "s3:GetBucketVersioning"
      ],
      "Resource": [
        "${aws_s3_bucket.autograder_artifacts.arn}",
        "${aws_s3_bucket.autograder_artifacts.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": [
        "ec2:CreateNetworkInterface",
        "ec2:DescribeNetworkInterfaces",
        "ec2:DeleteNetworkInterface",
        "ec2:DescribeSubnets",
        "ec2:DescribeSecurityGroups"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

resource "aws_codebuild_project" "autograder_project" {
  name         = "autograder-project"
  description  = "Build project for autograding student submissions"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    # VPC Configuration to run in isolated network
    vpc_config {
      vpc_id     = aws_vpc.autograder_vpc.id
      subnets    = [aws_subnet.autograder_subnet.id]
      security_group_ids = [aws_security_group.autograder_sg.id]
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example-org/student-repo.git" # Placeholder
    buildspec = "buildspec.yml"
  }

  # Note: In a real-world scenario with no outbound internet, fetching from GitHub 
  # at runtime requires a mechanism like a NAT (defeating the block) or pre-fetching to S3.
  # This configuration enforces the "block all outbound internet" via the security group and lack of NAT.
}
```

