# Data source to fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# Resource: EC2 Instance
# We tag this instance specifically to be picked up by the Backup selection
resource "aws_instance" "this" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"

  tags = {
    Name  = "BackupTestInstance"
    Backup = "True"
  }
}

# Resource: IAM Service Linked Role
# Required for AWS Backup to access resources on your behalf
resource "aws_iam_service_linked_role" "backup" {
  aws_service_name = "backup.amazonaws.com"
}

# Resource: Backup Vault
# A logical container where backups are stored
resource "aws_backup_vault" "daily_vault" {
  name = "ec2-daily-backup-vault"
}

# Resource: Backup Plan
# Defines the backup schedule and lifecycle
resource "aws_backup_plan" "daily_plan" {
  name = "ec2-12am-daily-plan"

  rule {
    name              = "daily_12am_rule"
    target_vault_name = aws_backup_vault.daily_vault.name

    # Schedule: Cron expression for 12:00 AM UTC every day
    schedule          = "cron(0 0 * * ? *)"

    start_window_minutes = 60
    completion_window_minutes = 180

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# Resource: Backup Selection
# Defines which resources are backed up by the plan
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_service_linked_role.backup.arn
  name         = "ec2-daily-selection"
  plan_id      = aws_backup_plan.daily_plan.id

  resources = []

  selection_tag {
    type  = "STRING_EQUALS"
    key   = "Backup"
    value = "True"
  }
}

