  rule = aws_cloudwatch_event_rule.cron.name
  arn  = aws_lambda_function.cron.arn
}

data "archive_file" "lambda-func" {
  type        = "zip"
  source_file = "./supplement/lambda_func.py"
  output_path = "./supplement/lambda_func.zip"
}

