extracted_code:
# Generate a unique suffix to ensure resource names are unique
resource "random_id" "suffix" {
  byte_length = 4
}

# 1. S3 Bucket: Origin storage for video files
resource "aws_s3_bucket" "video_origin" {
  bucket = "video-streaming-origin-${random_id.suffix.hex}"
}

# Ensure the S3 bucket is private and blocks public access
resource "aws_s3_bucket_public_access_block" "video_origin" {
  bucket = aws_s3_bucket.video_origin.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. CloudFront Origin Access Control (OAC)
# Secures access to the S3 bucket so content is only served through CloudFront
resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "video-streaming-oac-${random_id.suffix.hex}"
  description                       = "OAC for Video Streaming Platform"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 3. CloudFront Distribution: CDN for global content delivery
resource "aws_cloudfront_distribution" "streaming_cdn" {
  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Globally distributed video streaming CDN"
  default_root_object = "index.html"

  # Origin configuration pointing to the S3 bucket via OAC
  origin {
    domain_name              = aws_s3_bucket.video_origin.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
    origin_id                = "s3-origin"
  }

  # Default cache behavior
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "s3-origin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true
  }

  # Price class optimized for global delivery (use 200 for most regions, or 100 for cheapest)
  price_class = "PriceClass_All"

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  # SSL Configuration (Using default CloudFront certificate for simplicity)
  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# 4. Route 53 Hosted Zone: Managing the domain
resource "aws_route53_zone" "main" {
  name = "streaming-platform-example.com"
}

# 5. Route 53 Record: DNS Alias pointing to the CloudFront Distribution
resource "aws_route53_record" "cdn_alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "cdn.streaming-platform-example.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.streaming_cdn.domain_name
    zone_id                = aws_cloudfront_distribution.streaming_cdn.hosted_zone_id
    evaluate_target_health = true
  }
}

# 6. S3 Bucket Policy: Granting CloudFront read access via the OAC
resource "aws_s3_bucket_policy" "allow_cloudfront" {
  bucket = aws_s3_bucket.video_origin.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid      = "AllowCloudFrontOACAccess"
        Effect   = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_origin.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.streaming_cdn.arn
          }
        }
      }
    ]
  })
}

