extracted_code:
# Generate a random password for the database
resource "random_password" "db" {
  length  = 16
  special = false
}

# Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "protected-rds-vpc"
  }
}

# Create Private Subnets
resource "aws_subnet" "private_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "protected-rds-subnet-1"
  }
}

resource "aws_subnet" "private_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "protected-rds-subnet-2"
  }
}

# Create DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "protected-db-subnet-group"
  subnet_ids = [aws_subnet.private_1.id, aws_subnet.private_2.id]

  tags = {
    Name = "My DB subnet group"
  }
}

# Create KMS Key for encryption
resource "aws_kms_key" "rds_encryption" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
}

# Create Security Group
resource "aws_security_group" "rds" {
  name        = "protected-rds-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "protected-rds-sg"
  }
}

# Create Custom PostgreSQL Parameter Group
resource "aws_db_parameter_group" "custom_postgres" {
  name        = "custom-postgres-pg"
  family      = "postgres14"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }
}

# Create the RDS Instance
resource "aws_db_instance" "protected_postgres" {
  identifier             = "protected-postgres-instance"
  engine                 = "postgres"
  engine_version         = "14.9"
  instance_class         = "db.t3.medium"
  allocated_storage      = 20
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption.arn
  db_name                = "appdb"
  username               = "dbadmin"
  password               = random_password.db.result
  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  parameter_group_name   = aws_db_parameter_group.custom_postgres.name
  skip_final_snapshot    = true

  tags = {
    Environment = "production"
  }
}

