resource "random_password" "db" {
  length  = 16
  special = false
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

resource "aws_subnet" "subnets" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)

  tags = {
    Name = "aurora-subnet-${count.index}"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "aurora-subnet-group"
  }
}

resource "aws_security_group" "rds" {
  name        = "aurora-security-group"
  description = "Allow traffic from RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy.id]
  }

  tags = {
    Name = "aurora-sg"
  }
}

resource "aws_security_group" "proxy" {
  name        = "proxy-security-group"
  description = "Allow traffic to Aurora and from clients"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port       = 0
    to_port         = 0
    protocol        = "-1"
    security_groups = [aws_security_group.rds.id]
  }

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "proxy-sg"
  }
}

resource "aws_secretsmanager_secret" "db" {
  name = "aurora-master-secret"
}

resource "aws_secretsmanager_secret_version" "db" {
  secret_id = aws_secretsmanager_secret.db.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db.result
  })
}

resource "aws_iam_role" "proxy" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "proxy" {
  name = "rds-proxy-secret-policy"
  role = aws_iam_role.proxy.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Effect   = "Allow"
        Resource = aws_secretsmanager_secret.db.arn
      }
    ]
  })
}

resource "aws_rds_cluster" "aurora" {
  engine                = "aurora-mysql"
  engine_version        = "5.7.mysql_aurora.2.11.2"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.db.result
  db_subnet_group_name  = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  skip_final_snapshot   = true

  tags = {
    Name = "aurora-cluster"
  }
}

resource "aws_rds_cluster_instance" "aurora" {
  identifier         = "aurora-instance"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.aurora.engine
  publicly_accessible = false
}

resource "aws_db_proxy" "main" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = aws_subnet.subnets[*].id
  role_arn               = aws_iam_role.proxy.arn
  depends_on             = [aws_iam_role_policy.proxy]

  auth {
    auth_scheme = "SECRETS"
    secret_arn  = aws_secretsmanager_secret.db.arn
    iam_auth    = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "main" {
  db_proxy_name = aws_db_proxy.main.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent     = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["STRICT_SESSION_PINNING"]
  }
}

resource "aws_db_proxy_target" "rds" {
  db_proxy_name          = aws_db_proxy.main.name
  target_group_name      = aws_db_proxy_default_target_group.main.name
  db_cluster_identifier  = aws_rds_cluster.aurora.id
}

