```hcl
# Generate a secure password for the database
resource "random_password" "db" {
  length  = 16
  special = false
}

# Store credentials in AWS Secrets Manager
resource "aws_secretsmanager_secret" "db" {
  name = "aurora-cluster-secret"
}

resource "aws_secretsmanager_secret_version" "db" {
  secret_id     = aws_secretsmanager_secret.db.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db.result
  })
}

# Networking: VPC and Subnets
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "aurora-vpc"
  }
}

resource "aws_subnet" "main" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "aurora-subnet-${count.index}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.main[*].id

  tags = {
    Name = "My Aurora subnet group"
  }
}

# Security Groups
resource "aws_security_group" "db" {
  name        = "aurora-db-sg"
  description = "Allow traffic from RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "proxy" {
  name        = "aurora-proxy-sg"
  description = "Allow traffic to RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "proxy" {
  name = "aurora-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "proxy" {
  name = "aurora-proxy-policy"
  role = aws_iam_role.proxy.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Effect   = "Allow"
        Resource = aws_secretsmanager_secret.db.arn
      }
    ]
  })
}

# Aurora MySQL RDS Cluster
resource "aws_rds_cluster" "main" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.08.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.db.result
  db_subnet_group_name  = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db.id]
  skip_final_snapshot   = true

  # Ensure secret is created before DB
  depends_on = [aws_secretsmanager_secret_version.db]
}

resource "aws_rds_cluster_instance" "main" {
  identifier         = "aurora-instance-1"
  cluster_identifier = aws_rds_cluster.main.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.main.engine
  engine_version     = aws_rds_cluster.main.engine_version
}

# RDS Proxy
resource "aws_db_proxy" "main" {
  name                   = "aurora-proxy"
  engine                 = "aurora-mysql"
  role_arn               = aws_iam_role.proxy.arn
  vpc_subnet_ids         = aws_subnet.main[*].id
  vpc_security_group_ids = [aws_security_group.proxy.id]

  auth {
    auth_scheme = "SECRETS"
    secret_arn  = aws_secretsmanager_secret.db.arn
    iam_auth    = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "main" {
  db_proxy_name = aws_db_proxy.main.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent      = 100
    max_idle_connections_percent = 50
  }
}

resource "aws_db_proxy_target" "main" {
  db_proxy_name       = aws_db_proxy.main.name
  target_group_name   = aws_db_proxy_default_target_group.main.name
  db_cluster_identifier = aws_rds_cluster.main.id
}

# Data source for availability zones
data "aws_availability_zones" "available" {}
```

