  // engine              = "postgres"
  // engine_version      = "13"
  // instance_class_name = "db.t2.micro" (e.g., nano_2_0 or similar Lightsail bundle names like 'micro_2_0')

  // Note: AWS Lightsail databases do not expose an 'apply_immediately' setting in Terraform 
  // like AWS RDS does. Parameter changes are applied based on the parameter type (dynamic vs static).

  // Standard configuration for a PostgreSQL database on Lightsail:
  availability_zone      = "us-east-1a"
  engine                 = "postgres"
  engine_version         = "13"
  instance_class_name    = "nano_2_0" // Example instance plan
