  state              = "ENABLED"

  policy_details {
    resource_types = ["INSTANCE"]

    schedule {
      name = "Example Schedule"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
      }

      retain_rule {
        intervals      = 7
        interval_unit  = "DAYS"
      }

